  1	import * as React from 'react';
  2	import { cephStorageLabel } from '@odf/core/constants';
  3	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  4	import {
  5	  NodeModel,
  6	  PersistentVolumeClaimModel,
  7	  PersistentVolumeModel,
  8	  StorageClassModel,
  9	} from '@odf/shared/models';
 10	import {
 11	  getNodeStatusGroups,
 12	  getPVCStatusGroups,
 13	  getPVStatusGroups,
 14	} from '@odf/shared/status/Inventory';
 15	import {
 16	  K8sResourceKind,
 17	  StorageClassResourceKind,
 18	  PersistentVolumeClaimKind,
 19	} from '@odf/shared/types';
 20	import { NodeKind } from '@odf/shared/types';
 21	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 22	import { useK8sWatchResources } from '@openshift-console/dynamic-plugin-sdk';
 23	import { ResourceInventoryItem } from '@openshift-console/dynamic-plugin-sdk-internal';
 24	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 25	import {
 26	  getCephNodes,
 27	  filterCephPVCsByCluster,
 28	  filterCephPVsByCluster,
 29	} from '../../utils/common';
 30	
 31	const watchResources = {
 32	  nodes: {
 33	    isList: true,
 34	    kind: NodeModel.kind,
 35	  },
 36	  pvcs: {
 37	    isList: true,
 38	    kind: PersistentVolumeClaimModel.kind,
 39	  },
 40	  pvs: {
 41	    isList: true,
 42	    kind: PersistentVolumeModel.kind,
 43	  },
 44	  sc: {
 45	    isList: true,
 46	    kind: StorageClassModel.kind,
 47	  },
 48	};
 49	const InventoryCard: React.FC = () => {
 50	  const { t } = useCustomTranslation();
 51	
 52	  const { clusterNamespace: clusterNs } = useGetInternalClusterDetails();
 53	
 54	  const resources = useK8sWatchResources(watchResources);
 55	
 56	  const nodesLoaded = resources?.nodes?.loaded;
 57	  const nodesLoadError = resources?.nodes?.loadError;
 58	  const nodesData = (resources?.nodes?.data ?? []) as NodeKind[];
 59	
 60	  const pvcsLoaded = resources?.pvcs?.loaded;
 61	  const pvcsLoadError = resources?.pvcs?.loadError;
 62	  const pvcsData = (resources?.pvcs?.data ?? []) as PersistentVolumeClaimKind[];
 63	
 64	  const pvsLoaded = resources?.pvs?.loaded;
 65	  const pvsLoadError = resources?.pvs?.loadError;
 66	  const pvsData = (resources?.pvs?.data ?? []) as K8sResourceKind[];
 67	
 68	  const scData = (resources?.sc?.data ?? []) as StorageClassResourceKind[];
 69	  const ocsNodesHref = `/search?kind=${NodeModel.kind}&q=${cephStorageLabel(
 70	    clusterNs
 71	  )}`;
 72	
 73	  return (
 74	    <Card>
 75	      <CardHeader>
 76	        <CardTitle>{t('Inventory')}</CardTitle>
 77	      </CardHeader>
 78	      <CardBody>
 79	        <ResourceInventoryItem
 80	          dataTest="inventory-nodes"
 81	          isLoading={!nodesLoaded}
 82	          error={!!nodesLoadError}
 83	          kind={NodeModel as any}
 84	          resources={getCephNodes(nodesData, clusterNs)}
 85	          mapper={getNodeStatusGroups}
 86	          basePath={ocsNodesHref}
 87	        />
 88	        <ResourceInventoryItem
 89	          dataTest="inventory-pvc"
 90	          isLoading={!pvcsLoaded}
 91	          error={!!pvcsLoadError}
 92	          kind={PersistentVolumeClaimModel as any}
 93	          resources={filterCephPVCsByCluster(
 94	            scData,
 95	            pvcsData,
 96	            pvsData,
 97	            clusterNs
 98	          )}
 99	          mapper={getPVCStatusGroups}
100	          showLink={false}
101	        />
102	        <ResourceInventoryItem
103	          dataTest="inventory-pv"
104	          isLoading={!pvsLoaded}
105	          error={!!pvsLoadError}
106	          kind={PersistentVolumeModel as any}
107	          resources={filterCephPVsByCluster(pvsData, scData, clusterNs)}
108	          mapper={getPVStatusGroups}
109	          showLink={false}
110	        />
111	      </CardBody>
112	    </Card>
113	  );
114	};
115	
116	export default InventoryCard;

